import { IMessageEvent, MessageEvent } from '@nitrots/nitro-renderer/src/core';
import { DoorDashOrdersParser } from '@nitrots/nitro-renderer/src/nitro/communication/messages/parser/DoorDashOrdersParser';

export class DoorDashOrdersEvent extends MessageEvent implements IMessageEvent {
    constructor(callback: Function) {
        super(callback, DoorDashOrdersParser);
    }

    public getParser(): DoorDashOrdersParser {
        return this.parser as DoorDashOrdersParser;
    }
}
